INSERT OR IGNORE INTO posts (id, bbsid, board_id, user_id, title, content, content_text, signature, posted_at, reply_count, source_file, wayback_ts) VALUES (1229, 190445, 12, 34, '[转贴]第一次！', '回想起来，那是在三年前，具体时间记不得了（这种事都能忘？），应该是个礼拜六下午。她父母都不在家，她家里就我们两人……她的卧室里散回想起来，那是在三年前，具体时间记不得了（这种事都能忘？），应该是个礼拜六下午。她父母都不在家，她家里就我们两人……她的卧室里散发着一种淡淡的幽香（跟她身上的味一样），让人嗅之不免产生飘飘然的感觉。这是我初入女孩闺房，难免既好奇又紧张，只得极力掩饰，不想让她看出来。我尽量自然的在她身边坐下，手心已全是汗。“你真的想上？”她柔柔的笑道，表情轻松得让我吃惊。“嗯。”我觉得自己象个傻瓜。“你好象有点紧张，咯咯咯……”“没有！！！”我有一种被人看穿的恼羞成怒。“你以前从没上过？”她又柔柔的笑了。“是。”我不得不承认，我完全落了下风。“你叫我声‘姐姐’，我就让你上。”这让我想起了小时候，院子里那个常用棒棒糖逗我的傻大姐。我努力克制，不让自己发作。经过三秒钟的思想斗争，我屈服了，我是一个抗拒不了诱惑的人。“姐姐。”声音小得我担心她是否听见。“乖。“乖，来吧。”她第三次柔柔的笑了。我如同见到特赦令的囚犯，准确地说，是扑了过去，一把……“别急……嗯……不是这样的……轻点……”我终究是第一次，鼓捣半天也不得其道，有点急了…………………终于，她看不下去了，一把从我手里重新抢回鼠标，开始从头教我。如何拨号连接、如何打开浏览器、如何输入网址……，十分钟后，我全学会了。我可以向别人炫耀，我上过了！我会上了！以上是我第一次上网的痛苦回忆。忆苦思甜，同志们，要珍惜今天的幸福时光啊！！！', '回想起来，那是在三年前，具体时间记不得了（这种事都能忘？），应该是个礼拜六下午。她父母都不在家，她家里就我们两人……她的卧室里散回想起来，那是在三年前，具体时间记不得了（这种事都能忘？），应该是个礼拜六下午。她父母都不在家，她家里就我们两人……她的卧室里散发着一种淡淡的幽香（跟她身上的味一样），让人嗅之不免产生飘飘然的感觉。这是我初入女孩闺房，难免既好奇又紧张，只得极力掩饰，不想让她看出来。我尽量自然的在她身边坐下，手心已全是汗。“你真的想上？”她柔柔的笑道，表情轻松得让我吃惊。“嗯。”我觉得自己象个傻瓜。“你好象有点紧张，咯咯咯……”“没有！！！”我有一种被人看穿的恼羞成怒。“你以前从没上过？”她又柔柔的笑了。“是。”我不得不承认，我完全落了下风。“你叫我声‘姐姐’，我就让你上。”这让我想起了小时候，院子里那个常用棒棒糖逗我的傻大姐。我努力克制，不让自己发作。经过三秒钟的思想斗争，我屈服了，我是一个抗拒不了诱惑的人。“姐姐。”声音小得我担心她是否听见。“乖。“乖，来吧。”她第三次柔柔的笑了。我如同见到特赦令的囚犯，准确地说，是扑了过去，一把……“别急……嗯……不是这样的……轻点……”我终究是第一次，鼓捣半天也不得其道，有点急了…………………终于，她看不下去了，一把从我手里重新抢回鼠标，开始从头教我。如何拨号连接、如何打开浏览器、如何输入网址……，十分钟后，我全学会了。我可以向别人炫耀，我上过了！我会上了！以上是我第一次上网的痛苦回忆。忆苦思甜，同志们，要珍惜今天的幸福时光啊！！！', NULL, '2002-12-02 12:14:00', 0, '20021230094335_bbsid_190445_board_12_7a01f56a89.html', '20021230094335');
